{"file_path":"D:\project\ai\新建文件夹 (2)\my-blog\src\components\Navbar.js","content":"import React, { useState, useEffect } from 'react';

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
      <div className="nav-logo">🦆 黎大白</div>
      <div className="nav-links">
        <a href="#home">首页</a>
        <a href="#about">关于</a>
        <a href="#skills">技能</a>
        <a href="#blog">博客</a>
        <a href="#contact">联系</a>
      </div>
    </nav>
  );
};

export default Navbar;
"}

