{"file_path":"D:\project\ai\新建文件夹 (2)\my-blog\src\components\Contact.js","content":"import React, { useState } from 'react';

const Contact = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    alert('感谢您的留言！我会尽快回复您。');
    setFormData({ name: '', email: '', message: '' });
  };

  return (
    <section className="contact" id="contact">
      <div className="container">
        <h2 className="section-title">联系我</h2>
        <p className="section-subtitle">期待与您的交流</p>

        <div className="contact-content">
          <div className="contact-info">
            <h3>让我们一起创造精彩</h3>
            <p>
              无论是技术讨论、项目合作，还是音乐交流，我都很乐意与您沟通。
              欢迎通过以下方式联系我，我会尽快回复！
            </p>

            <div className="contact-methods">
              <div className="contact-method">
                <div className="contact-icon">📧</div>
                <span>contact@lidabai.com</span>
              </div>
              <div className="contact-method">
                <div className="contact-icon">📍</div>
                <span>中国</span>
              </div>
              <div className="contact-method">
                <div className="contact-icon">🌐</div>
                <span>github.com/lidabai</span>
              </div>
            </div>
          </div>

          <form className="contact-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label>您的姓名</label>
              <input 
                type="text" 
                name="name" 
                value={formData.name}
                onChange={handleChange}
                placeholder="请输入您的姓名"
                required
              />
            </div>
            <div className="form-group">
              <label>电子邮箱</label>
              <input 
                type="email" 
                name="email" 
                value={formData.email}
                onChange={handleChange}
                placeholder="请输入您的邮箱"
                required
              />
            </div>
            <div className="form-group">
              <label>留言内容</label>
              <textarea 
                name="message" 
                value={formData.message}
                onChange={handleChange}
                placeholder="请输入您想说的话..."
                required
              ></textarea>
            </div>
            <button type="submit" className="btn-submit">发送留言 ✨</button>
          </form>
        </div>
      </div>
    </section>
  );
};

export default Contact;
"}
